+fn builtin_overlay_module_key(base: &str, canonical: &str) -> String {
+    let mut hasher = Sha256::new();
+    hasher.update(base.as_bytes());
+    let digest = format!("{:x}", hasher.finalize());
+    let short = &digest[..16];
+    format!("pijs-compat://builtin/{canonical}/{short}")
+}
